import mujoco, numpy as np, time
base=open("model_ref.xml").read()
def make(opt):
    return mujoco.MjModel.from_xml_string(base.replace('<compiler autolimits="true"/>','<compiler autolimits="true"/>\n  '+opt))
def sim(model, seed):
    data=mujoco.MjData(model); nstep=int(2.0/model.opt.timestep)
    rng=np.random.default_rng(seed); data.qpos+=rng.normal(0,0.01,size=data.qpos.shape)
    mujoco.mj_forward(model,data)
    for _ in range(nstep): mujoco.mj_step(model,data)
    s=np.zeros(mujoco.mj_stateSize(model,mujoco.mjtState.mjSTATE_FULLPHYSICS))
    mujoco.mj_getState(model,data,s,mujoco.mjtState.mjSTATE_FULLPHYSICS); return s
ref=mujoco.MjModel.from_xml_path("model_ref.xml")
def one(model):
    seed=np.random.randint(0,10000); t=time.perf_counter(); sim(model,seed); return time.perf_counter()-t
opts=[
 '<option jacobian="dense" solver="PGS" iterations="2"><flag contact="disable"/></option>',
 '<option jacobian="dense" solver="PGS" iterations="5"><flag contact="disable"/></option>',
 '<option jacobian="dense" solver="PGS" iterations="10"><flag contact="disable"/></option>',
 '<option jacobian="dense" solver="PGS" iterations="20"><flag contact="disable"/></option>',
]
mods=[make(o) for o in opts]
seeds=np.random.randint(0,10000,size=12)
for o,m in zip(opts,mods):
    ds=[np.linalg.norm(sim(m,int(s))-sim(ref,int(s))) for s in seeds]
    print("maxdiff %.2e mean %.2e  %s"%(max(ds),np.mean(ds),o[40:75]))
ratios={i:[] for i in range(len(mods))}
for rep in range(30):
    tr=one(ref)
    for i,m in enumerate(mods): ratios[i].append(one(m)/tr)
for i,o in enumerate(opts):
    r=np.array(ratios[i]); print("pctg med %.3f mean %.3f  %s"%(np.median(r),r.mean(),o[40:75]))
