import mujoco, numpy as np
base=open("model_ref.xml").read()
def make(opt=None):
    x=base if opt is None else base.replace('<compiler autolimits="true"/>','<compiler autolimits="true"/>\n  '+opt)
    return mujoco.MjModel.from_xml_string(x)
def run(model,label):
    data=mujoco.MjData(model)
    rng=np.random.default_rng(1); data.qpos+=rng.normal(0,0.01,size=data.qpos.shape)
    mujoco.mj_forward(model,data)
    for _ in range(1000): mujoco.mj_step(model,data)
    names=['step','forward','inverse','pos','vel','actuation','constraint','advance','pos_kinematics','pos_inertia','pos_collision','pos_make','pos_project']
    print("==",label)
    for i,n in enumerate(names):
        t=model.opt.timestep # dummy
    for i in range(mujoco.mjtTimer.mjNTIMER):
        d=data.timer[i]
        if d.number>0:
            print("  %2d dur/step %.2f us  n %d"%(i, d.duration/d.number, d.number))
run(make(),"REF")
run(make('<option jacobian="dense" solver="PGS" iterations="10"><flag contact="disable"/></option>'),"PGS")
